    title: "ETL 蓝图 v1：数据目录 & 运维手册",
    tags: ["ETL", "数据目录", "Runbook", "脚本", "调度", "运维", "AKShare", "宏观指标", "采集"],
    createdAt: "2026-02-27T04:07:37.480Z",
